const body = $json || {};

const allowedQueues = new Set(['realtime', 'business', 'analytics']);
const allowedOps = new Set(['insert', 'upsert']);

const queue_name = body.queue_name || 'business';
const op = body.query_operation || 'upsert';
const target_db = body.target_db;
const target_table = body.target_table;
const dedup_key = body.dedup_key || null;
const payload = body.payload;

if (!allowedQueues.has(queue_name)) throw new Error(`queue_name inválida: ${queue_name}`);
if (!allowedOps.has(op)) throw new Error(`op inválida: ${op}`);
if (!target_db || !target_table) throw new Error('target_db e target_table são obrigatórios');
if (!payload || typeof payload !== 'object' || Array.isArray(payload)) throw new Error('payload deve ser um objeto');

// String JSON válida (isso aqui é o que vai pro MySQL)
const payload_json = JSON.stringify(payload);

// Plano B: string já escapada pra SQL literal (se você precisar usar sem Query Parameters)
const payload_sql = payload_json.replace(/\\/g, '\\\\').replace(/'/g, "\\'");

if (payload_json.length > 200000) throw new Error(`payload grande demais (${payload_json.length} bytes)`);

// Base64 para não quebrar no Query Parameters do n8n
const payload_b64 = Buffer.from(payload_json, 'utf8').toString('base64');

return {
  json: {
    queue_name,
    op,
    target_db,
    target_table,
    dedup_key,
    payload_json,
    payload_sql,
    payload_b64,
  }
};

function esc(v) {
  if (v === null || v === undefined) return 'NULL';

  if (typeof v === 'object') {
    const sObj = JSON.stringify(v);
    const sEsc = sObj.replace(/\\/g,'\\\\').replace(/'/g,"\\'");
    return `'${sEsc}'`;
  }

  const s = String(v).replace(/\\/g,'\\\\').replace(/'/g,"\\'");
  return `'${s}'`;
}

function ident(s) {
  return String(s || '').replace(/[^a-zA-Z0-9_]/g, '');
}

function decodePayload(row) {
  if (!row.payload) throw new Error('payload vazio');

  let p = String(row.payload).trim();

  // 1) Se vier com envelope do n8n (ex: base64:type15:...)
  if (p.startsWith('base64:')) {
    // pega tudo depois do último ":" (cobre base64:type15:)
    p = p.substring(p.lastIndexOf(':') + 1);
  }

  // 2) Remove quebras de linha / espaços do base64
  p = p.replace(/\s+/g, '');

  // 3) Se for JSON puro (debug manual), não decodifica
  if (p.startsWith('{')) return JSON.parse(p);

  // 4) Decodifica base64 -> utf8 -> JSON
  const jsonStr = Buffer.from(p, 'base64').toString('utf8').trim();

  return JSON.parse(jsonStr);
}


const jobId = $json.id;

try {
  const db = ident($json.target_db);
  const table = ident($json.target_table);
  const op = $json.op;

  if (!db || !table) throw new Error('target_db/target_table inválidos');
  if (op !== 'insert' && op !== 'upsert') throw new Error('op inválida');

  const payload = decodePayload($json);

  const colsRaw = Object.keys(payload);
  if (colsRaw.length === 0) throw new Error('payload vazio');

  const cols = colsRaw.map(ident).filter(Boolean);
  if (cols.length === 0) throw new Error('nenhuma coluna válida');

  const colList = cols.map(c => `\`${c}\``).join(', ');
  const valList = cols.map(c => esc(payload[c])).join(', ');

  let sql_query;

  if (op === 'insert') {
    sql_query = `INSERT INTO \`${db}\`.\`${table}\` (${colList}) VALUES (${valList});`;
  } else {
    const updates = cols.map(c => `\`${c}\`=VALUES(\`${c}\`)`).join(', ');
    sql_query = `INSERT INTO \`${db}\`.\`${table}\` (${colList}) VALUES (${valList}) ON DUPLICATE KEY UPDATE ${updates};`;
  }

  return { json: { ok: true, jobId, sql_query } };

} catch (e) {
  return { json: { ok: false, jobId, error: e.message || String(e) } };
}

